            <div class="card__body">
              <div class="card__header-row">
                <div class="card__header-text">
                  <div class="card__meta">
                    <time class="card__date" [attr.datetime]="item.date">{{ item.date | date:'mediumDate' }}</time>
                  </div>
                  @switch (headingLevel()) {
                    @case (2) { <h2 class="card__title" [attr.lang]="getItemLang(item)">{{ item.title }}</h2> }
                    @default { <h3 class="card__title" [attr.lang]="getItemLang(item)">{{ item.title }}</h3> }
                  }
                </div>
                @if (item.publishedAt?.logo) {
                  <span class="card__published-at">
                    <img
                      class="card__published-at-logo"
                      [src]="item.publishedAt.logo"
                      [alt]="''"
                      width="96"
                      height="96"
                    />
                    <span class="visually-hidden" i18n="card label|Published at source@@contentCard.publishedAt.seriesLabel">Veröffentlicht auf {{ item.publishedAt.name }}</span>
                  </span>
                }
              </div>
              <p class="card__description" [attr.lang]="getItemLang(item)">{{ item.description }}</p>
            </div>
          </a>
        </div>
      }
    </app-series-pagination-carousel>
  </article>
} @else {
  <article class="card">
    <a class="card__link" [appSmartLink]="routeLink()" [externalUrl]="externalUrl()" [hreflang]="hreflang()" [ariaLabel]="title()">
      @if (thumbnailSrc()) {
        <div class="card__image-wrapper">
          <img
            [ngSrc]="thumbnailSrc()!"
            alt=""
            class="card__image"
            fill
            [priority]="priority()"
          />
          @if (externalUrl()) {
            <span class="card__external-badge" aria-hidden="true">
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"/><polyline points="15 3 21 3 21 9"/><line x1="10" y1="14" x2="21" y2="3"/></svg>
            </span>
          }
        </div>
      }
      <div class="card__body">
        <div class="card__header-row">
          <div class="card__header-text">
            <div class="card__meta">
              @if (isUpcoming()) {
                <span class="card__upcoming-badge" i18n="badge label|Upcoming event badge@@contentCard.upcoming.badge">Bevorstehend</span>
              }
              @if (status()) {
                <app-status-badge [status]="status()!" />
              }
              @if (eventName()) {
                <span class="card__event">{{ eventName() }}</span>
              }
              <time class="card__date" [attr.datetime]="date()">{{ date() | date:'mediumDate' }}</time>
            </div>
            @switch (headingLevel()) {
              @case (2) { <h2 class="card__title" [attr.lang]="contentLang()">{{ title() }}</h2> }
              @default { <h3 class="card__title" [attr.lang]="contentLang()">{{ title() }}</h3> }
            }
          </div>
          @if (publishedAt()?.logo) {
            <span class="card__published-at">
              <img
                class="card__published-at-logo"
                [src]="publishedAt()!.logo!"
                [alt]="''"
                width="96"
                height="96"
              />
              <span class="visually-hidden" i18n="card label|Published at source@@contentCard.publishedAt.label">Veröffentlicht auf {{ publishedAt()!.name }}</span>
            </span>
          }
        </div>
        <p class="card__description" [attr.lang]="contentLang()">{{ description() }}</p>
      </div>
    </a>
  </article>
}

