import {
  ChangeDetectionStrategy,
  Component,
  computed,
  effect,
  inject,
  LOCALE_ID,
} from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs';
import { DatePipe } from '@angular/common';
import { MarkdownContent } from '../../components/markdown-content/markdown-content';
import { PublishedAtBanner } from '../../components/published-at-banner/published-at-banner';
import { ContentDetailLayout } from '../../layouts/content-detail-layout/content-detail-layout';
import { MetaManager } from '../../services/meta/meta';
import { Content } from '../../services/content/content';

@Component({
  selector: 'app-talk-detail-page',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [MarkdownContent, PublishedAtBanner, ContentDetailLayout, DatePipe],
  templateUrl: './talk-detail-page.html',
  styleUrl: './talk-detail-page.css',
})
export class TalkDetailPage {
  private readonly route = inject(ActivatedRoute);
  private readonly metaService = inject(MetaManager);
  private readonly contentService = inject(Content);
  private readonly localeId = inject(LOCALE_ID);

  private readonly slug = toSignal(
    this.route.paramMap.pipe(map((params) => params.get('slug') ?? '')),
    { initialValue: '' },
  );

  readonly talk = computed(() => {
    const currentSlug = this.slug();
    return this.contentService.getTalk(currentSlug) ?? null;
  });

  protected readonly contentLang = computed(() => {
    const t = this.talk();
    return t?.language && t.language !== this.localeId ? t.language : null;
  });

  protected readonly isUpcoming = computed(() => {
    const t = this.talk();
    if (!t) return false;
    const eventDate = new Date(t.date + 'T23:59:59');
    return eventDate > new Date();
  });

  constructor() {
    effect(() => {
      const currentTalk = this.talk();
      if (currentTalk) {
        this.metaService.updateMeta({
          title: currentTalk.title,
          description: currentTalk.description,
          url: `https://k9n.dev/talks/${currentTalk.slug}`,
          type: 'article',
        });
      }
    });
  }
}

components.templateData:
@if (talk(); as talk) {
  <app-content-detail-layout>
    <div slot="header">
      <div class="talk-detail__meta">
        @if (isUpcoming()) {
          <span class="talk-detail__upcoming-badge" i18n="badge label|Upcoming event badge@@page.talkDetail.upcoming.badge">Bevorstehend</span>
        }
        <span class="talk-detail__event">{{ talk.event }}</span>
        <time class="talk-detail__date" [attr.datetime]="talk.date">{{
          talk.date | date:'mediumDate'
        }}</time>
      </div>
      <h1 class="talk-detail__title" [attr.lang]="contentLang()">{{ talk.title }}</h1>
      <p class="talk-detail__description" [attr.lang]="contentLang()">{{ talk.description }}</p>
    </div>

    <div slot="content">
      <div [attr.lang]="contentLang()">
        <app-markdown-content [content]="talk.content" />
      </div>

      <app-published-at-banner
        [publishedAt]="talk.publishedAt"
        [linked]="talk.linked"
      />

      @if (talk.links && talk.links.length > 0) {
        <aside class="talk-detail__links" aria-label="Externe Ressourcen" i18n-aria-label="@@page.talkDetail.resources.ariaLabel">
          <h2 class="talk-detail__links-heading" i18n="section heading|Talk resources heading@@page.talkDetail.resources.heading">Ressourcen</h2>
          <ul class="talk-detail__links-list">
            @for (link of talk.links; track link.url) {
              <li>
                <a
                  [href]="link.url"
                  target="_blank"
                  rel="noopener noreferrer"
                  class="talk-detail__link"
                >
                  {{ link.label }}
                  <span class="talk-detail__link-icon" aria-hidden="true">↗</span>
                </a>
              </li>
            }
          </ul>
        </aside>
      }
    </div>
  </app-content-detail-layout>
} @else {
  <section class="not-found">
    <h1 class="not-found__title" i18n="not found title|Talk not found title@@page.talkDetail.notFound.title">Vortrag nicht gefunden</h1>
    <p class="not-found__text" i18n="not found message|Talk not found message@@page.talkDetail.notFound.message">
      Der gesuchte Vortrag existiert nicht.
    </p>
    <a href="/talks" class="not-found__link" i18n="not found link|Back to talks link@@page.talkDetail.notFound.backLink">← Zurück zu allen Vorträgen</a>
  </section>
}

